mapper.select:
select id, user_id, tool_id, type, create_by, create_time, update_by, update_time, delete_flag
from osh_tool_vote
where user_id = #{userId}
  and tool_id = #{toolId}
limit 1

select type
from osh_tool_vote
where user_id = #{userId}
  and tool_id = #{toolId}
  and delete_flag = 0
limit 1

